INSERT INTO [Courses] ([CourseID], [CategoryID], [CourseCode], [Title], [Description], [Thumbnail], [IsMandatory], [Status], [Level], [CreatedBy], [TargetDepartmentID], [OwnerDepartmentID], [IsForAllDepartments], [TargetDepartmentIds], [CreatedAt], [StartDate], [EndDate]) VALUES (57, 24, N'Test01', N'Khóa học: Nâng Cấp Kỹ Năng Kỹ năng tiêu chuẩn của 1 tester trong dự án', N'học cách test tiêu chuẩn của 1 dự án', N'https://images.unsplash.com/photo-1590486803833-1c5dc8ddd4c8?auto=format&fit=crop&w=400&q=80', 1, N'Active', 1, 89, NULL, 33, 1, N'', '2026-06-12 23:16:42.437', '2026-06-17 00:00:00.000', '2026-06-19 00:00:00.000');
INSERT INTO [Courses] ([CourseID], [CategoryID], [CourseCode], [Title], [Description], [Thumbnail], [IsMandatory], [Status], [Level], [CreatedBy], [TargetDepartmentID], [OwnerDepartmentID], [IsForAllDepartments], [TargetDepartmentIds], [CreatedAt], [StartDate], [EndDate]) VALUES (58, 22, N'PRO102', N'Quy trình Vận hành Máy & Tiêu chuẩn 5S', N'Hướng dẫn công nhân cách vận hành máy móc an toàn, các bước bảo trì hàng ngày và áp dụng phương pháp 5S (Sàng lọc, Sắp xếp, Sạch sẽ, Săn sóc, Sẵn sàng) tại vị trí sản xuất.', N'https://images.unsplash.com/photo-1581091226825-a6a2a5aee158?auto=format&fit=crop&w=400&q=80', 1, N'Published', 1, 89, 33, 33, 0, NULL, '2026-06-12 23:16:42.437', NULL, NULL);
INSERT INTO [Courses] ([CourseID], [CategoryID], [CourseCode], [Title], [Description], [Thumbnail], [IsMandatory], [Status], [Level], [CreatedBy], [TargetDepartmentID], [OwnerDepartmentID], [IsForAllDepartments], [TargetDepartmentIds], [CreatedAt], [StartDate], [EndDate]) VALUES (59, 25, N'ITSEC101', N'An ninh thông tin & Phòng ngừa Phishing', N'Nâng cao nhận thức bảo mật, quy tắc đặt mật khẩu mạnh, nhận biết các email giả mạo và phương án báo cáo sự cố an ninh thông tin cho bộ phận IT.', N'https://images.unsplash.com/photo-1550751827-4bd374c3f58b?auto=format&fit=crop&w=400&q=80', 1, N'Published', 1, 103, 32, 36, 1, N'32', '2026-06-12 23:16:42.437', NULL, NULL);
INSERT INTO [Courses] ([CourseID], [CategoryID], [CourseCode], [Title], [Description], [Thumbnail], [IsMandatory], [Status], [Level], [CreatedBy], [TargetDepartmentID], [OwnerDepartmentID], [IsForAllDepartments], [TargetDepartmentIds], [CreatedAt], [StartDate], [EndDate]) VALUES (60, 21, N'SALES201', N'Kỹ năng Bán hàng & Chăm sóc Khách hàng', N'Quy trình tìm kiếm, tiếp cận khách hàng tiềm năng, kỹ năng telesales và đàm phán xử lý từ chối chuyên nghiệp để chốt hợp đồng hiệu quả.', N'https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=400&q=80', 0, N'Published', 2, 96, 34, 34, 0, NULL, '2026-06-12 23:16:42.437', NULL, NULL);
INSERT INTO [Courses] ([CourseID], [CategoryID], [CourseCode], [Title], [Description], [Thumbnail], [IsMandatory], [Status], [Level], [CreatedBy], [TargetDepartmentID], [OwnerDepartmentID], [IsForAllDepartments], [TargetDepartmentIds], [CreatedAt], [StartDate], [EndDate]) VALUES (61, 26, N'FIN201', N'Quy trình Thanh toán & Tạm ứng Nội bộ', N'Hướng dẫn chi tiết quy chế lập chứng từ hóa đơn, quy trình trình duyệt tạm ứng và quyết toán chi phí công tác dành cho toàn thể nhân viên.', N'https://images.unsplash.com/photo-1454165804606-c3d57bc86b40?auto=format&fit=crop&w=400&q=80', 0, N'Active', 1, 100, 32, 35, 1, N'32', '2026-06-12 23:16:42.437', '2026-06-27 00:00:00.000', '2026-07-11 00:00:00.000');
