INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (87, 74, N'Bài 1: Nội quy an toàn chung tại nhà máy', N'Text', N'<h1>Nội quy an toàn lao động nhà máy</h1><p>1. Tất cả nhân viên và khách tham quan phải mặc trang phục bảo hộ phù hợp khi bước vào khu vực sản xuất.</p><p>2. Không vận hành bất kỳ thiết bị nào khi chưa được đào tạo hoặc hướng dẫn cụ thể từ tổ trưởng.</p><p>3. Tuyệt đối tuân thủ biển cảnh báo và rào chắn an toàn.</p>', N'https://www.w3schools.com/html/mov_bbb.mp4', 1, 1);
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (88, 74, N'Bài 2: Sử dụng trang thiết bị bảo hộ cá nhân (PPE)', N'Text', N'<h1>Hướng dẫn sử dụng PPE đúng cách</h1><p>PPE bao gồm: Mũ bảo hộ, Kính an toàn, Nút tai chống ồn, Găng tay bảo hộ và Giày mũi sắt chống đinh.</p><p>Nhân viên có trách nhiệm kiểm tra thiết bị bảo hộ của mình trước mỗi ca làm việc để phát hiện hư hỏng kịp thời.</p>', N'', 1, 2);
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (89, 75, N'Bài 1: Quy trình ứng phó khi có hỏa hoạn xảy ra', N'Text', N'<h1>Hệ thống phòng cháy chữa cháy</h1><p>Trong trường hợp có còi báo cháy: Ngắt nguồn điện máy móc gần nhất, di chuyển nhanh ra lối thoát hiểm gần nhất theo chỉ dẫn đèn Exit.</p>', N'https://www.w3schools.com/html/movie.mp4', 1, 1);
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (90, 75, N'Bài 2: Kỹ thuật sử dụng bình chữa cháy CO2 và bình bột', N'Text', N'<h1>Sử dụng bình cứu hỏa xách tay</h1><p>Sử dụng quy tắc PASS khi dùng bình cứu hỏa: Pull pin (Rút chốt) - Aim low (Hướng vòi vào gốc lửa) - Squeeze lever (Bóp cò) - Sweep (Quét qua lại).</p>', N'', 1, 2);
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (91, 76, N'Bài 1: Quy tắc an toàn điện trong vận hành máy móc', N'Text', N'<h1>Nguyên tắc an toàn điện</h1><p>Không dùng tay ướt cắm phích điện hoặc chạm vào tủ điện chính. Bảo đảm thiết bị đã được nối đất và có aptomat chống giật.</p>', N'https://www.w3schools.com/html/mov_bbb.mp4', 1, 1);
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (92, 76, N'Bài 2: Xử lý sự cố rò rỉ hóa chất và sơ cứu ban đầu', N'Text', N'<h1>Quy trình xử lý hóa chất tràn đổ</h1><p>Khi hóa chất tràn đổ, khoanh vùng rò rỉ, dùng cát thấm chất lỏng và đeo khẩu trang chống hơi độc để dọn dẹp. Rửa sạch da/mắt dưới vòi nước sạch 15 phút nếu dính hóa chất.</p>', N'', 1, 2);
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (93, 77, N'Bài 1: 5S là gì? Thực hành Seiri, Seiton, Seiso, Seiketsu, Shitsuke', N'Text', N'<h1>Khái niệm 5S Nhật Bản</h1><p>1. Seiri (Sàng lọc): Loại bỏ vật dụng không cần thiết.<br>2. Seiton (Sắp xếp): Đặt vật dụng đúng nơi quy định.<br>3. Seiso (Sạch sẽ): Lau chùi vệ sinh máy móc hàng ngày.<br>4. Seiketsu (Săn sóc): Duy trì và chuẩn hóa 3S trên.<br>5. Shitsuke (Sẵn sàng): Tạo thói quen tự giác tuân thủ.</p>', N'https://www.w3schools.com/html/movie.mp4', 1, 1);
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (94, NULL, N'Bài 1: Quy trình khởi động, kiểm tra và tắt máy an toàn', N'Text', N'<h1>Vận hành máy đúng kỹ thuật</h1><p>Bước 1: Kiểm tra ngoại quan máy và dây dẫn điện.<br>Bước 2: Bật công tắc nguồn chính.<br>Bước 3: Nhấn nút Start. Lưu ý luôn giữ tay khô ráo khi thao tác điện.<br>Khi hoàn thành ca hoặc có sự cố, nhấn nút dừng khẩn cấp (Emergency Stop) để dừng máy ngay lập tức.</p>', N'', 1, 1);
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (95, 117, N'Bài 1: Nguyên tắc đặt mật khẩu mạnh và bảo mật đa lớp (MFA)', N'Text', N'<h1>Quy tắc đặt mật khẩu mạnh</h1><p>Mật khẩu tối thiểu 8 ký tự, kết hợp chữ hoa, chữ thường, số và ký tự đặc biệt. Kích hoạt tính năng MFA (xác thực đa nhân tố) trên tài khoản làm việc của công ty.</p>', N'https://www.w3schools.com/html/mov_bbb.mp4', 1, 1);
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (96, 80, N'Bài 1: Cách kiểm tra liên kết lạ và xử lý khi nghi ngờ bị tấn công Phishing', N'Text', N'<h1>Phòng chống Phishing email</h1><p>Phishing là hình thức kẻ giả danh đối tác, sếp dụ người dùng nhấp vào link độc hại. Quy tắc vàng: Không nhấp link lạ trong email khẩn cấp, di chuột lên link để xem URL thực tế.</p>', N'', 1, 1);
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (97, 81, N'Bài 1: Xác định chân dung khách hàng và kỹ thuật chào hàng qua điện thoại (Telesales)', N'Text', N'<h1>Tìm kiếm Khách hàng</h1><p>Phân tích nhu cầu của doanh nghiệp để vẽ chân dung khách hàng. Chuẩn bị kịch bản cuộc gọi điện thoại chào hàng, hướng tới mục tiêu thiết lập một buổi hẹn gặp trực tiếp.</p>', N'https://www.w3schools.com/html/movie.mp4', 2, 1);
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (98, 82, N'Bài 1: Các tình huống từ chối phổ biến và phương pháp đàm phán thuyết phục', N'Text', N'<h1>Xử lý từ chối trong bán hàng</h1><p>Khi khách hàng từ chối về giá, hãy nhấn mạnh giá trị sản phẩm mang lại so với đối thủ và đưa ra bài toán lợi ích kinh tế lâu dài thay vì giảm giá vội vàng.</p>', N'', 2, 1);
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (99, 83, N'Bài 1: Cách phân biệt hóa đơn GTGT hợp pháp và chứng từ thanh toán hợp lệ', N'Text', N'<h1>Hóa đơn chứng từ kế toán</h1><p>Hóa đơn mua hàng từ 20 triệu trở lên bắt buộc phải chuyển khoản qua tài khoản ngân hàng của công ty. Hóa đơn GTGT đầu vào phải ghi chính xác tên doanh nghiệp và mã số thuế.</p>', N'https://www.w3schools.com/html/mov_bbb.mp4', 1, 1);
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (100, 84, N'Bài 1: Hướng dẫn lập đề nghị tạm ứng, duyệt chi và hoàn ứng đúng thời hạn', N'Text', N'<h1>Tạm ứng và hoàn ứng</h1><p>Nhân viên lập phiếu đề xuất tạm ứng chi phí công tác được duyệt bởi trưởng phòng. Hoàn ứng trong vòng tối đa 5 ngày làm việc sau khi kết thúc công tác kèm đầy đủ hóa đơn chứng từ.</p>', N'', 1, 1);
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (122, NULL, N'BÀI 1.1: Tầm quan trọng của việc bảo mật', N'Document', N'<p>1. Trong thời đại số, dữ liệu là tài sản quý giá nhất của doanh nghiệp. Rò rỉ thông tin có thể gây ra thiệt hại tài chính nghiêm trọng và làm mất uy tín thương hiệu. Nhân viên là tuyến phòng thủ đầu tiên và cũng là mục tiêu tấn công hàng đầu của các hacker.</p>
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (123, NULL, N'BÀI 1.2: Các hình thức tấn công phổ biến', N'Document', N'<p>Nội dung bài học: Phishing (tấn công giả mạo) qua email là hình thức phổ biến nhất. Hacker sẽ gửi email giả mạo các tổ chức uy tín (như ngân hàng, bộ phận IT) để lừa nhân viên click vào link độc hại hoặc cung cấp mật khẩu. Ngoài ra còn có mã độc tống tiền (Ransomware) mã hóa dữ liệu của máy tính.</p>
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (124, NULL, N'BÀI 2.1: Cách đặt mật khẩu an toàn', N'Document', N'<p>Nội dung bài học: Mật khẩu an toàn phải có độ dài tối thiểu 12 ký tự, bao gồm chữ hoa, chữ thường, chữ số và ký tự đặc biệt. Tuyệt đối không dùng thông tin cá nhân như ngày sinh, số điện thoại để đặt mật khẩu. Nên sử dụng phần mềm quản lý mật khẩu (Password Manager) để lưu trữ.</p>
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (131, NULL, N'BÀI 1.1: Tầm quan trọng của việc bảo mật', N'Document', N'<p>1. Trong thời đại số, dữ liệu là tài sản quý giá nhất của doanh nghiệp. Rò rỉ thông tin có thể gây ra thiệt hại tài chính nghiêm trọng và làm mất uy tín thương hiệu. Nhân viên là tuyến phòng thủ đầu tiên và cũng là mục tiêu tấn công hàng đầu của các hacker.</p>
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (132, NULL, N'BÀI 1.2: Các hình thức tấn công phổ biến', N'Document', N'<p>Nội dung bài học: Phishing (tấn công giả mạo) qua email là hình thức phổ biến nhất. Hacker sẽ gửi email giả mạo các tổ chức uy tín (như ngân hàng, bộ phận IT) để lừa nhân viên click vào link độc hại hoặc cung cấp mật khẩu. Ngoài ra còn có mã độc tống tiền (Ransomware) mã hóa dữ liệu của máy tính.</p>
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (133, NULL, N'BÀI 2.1: Cách đặt mật khẩu an toàn', N'Document', N'<p>Nội dung bài học: Mật khẩu an toàn phải có độ dài tối thiểu 12 ký tự, bao gồm chữ hoa, chữ thường, chữ số và ký tự đặc biệt. Tuyệt đối không dùng thông tin cá nhân như ngày sinh, số điện thoại để đặt mật khẩu. Nên sử dụng phần mềm quản lý mật khẩu (Password Manager) để lưu trữ.</p>
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (134, NULL, N'BÀI 1.1: Xây dựng kịch bản Telesale', N'Document', N'<p>Nội dung bài học: Kịch bản là xương sống của cuộc gọi. Một kịch bản chuẩn gồm 4 phần: Chào hỏi gây ấn tượng, Đặt câu hỏi khai thác nhu cầu, Đưa ra giải pháp/giá trị nổi bật, và Kêu gọi hành động (CTA). Giáo viên cần tập luyện để giọng nói tự nhiên, không đọc nguyên văn kịch bản.</p>
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (135, NULL, N'BÀI 1.2: Chuẩn bị tâm lý và năng lượng', N'Document', N'<p>Nội dung bài học: Khách hàng có thể cảm nhận được cảm xúc của bạn qua giọng nói. Trước khi gọi, hãy hít thở sâu, ngồi thẳng lưng và luôn nở nụ cười. Giọng nói cần rõ ràng, tốc độ vừa phải, tràn đầy năng lượng tích cực.</p>
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (136, NULL, N'BÀI 2.1: Quy tắc lắng nghe và đồng cảm', N'Document', N'<p>Nội dung bài học: Khi khách hàng từ chối (ví dụ: ''Anh bận lắm'', ''Giá đắt quá''), tuyệt đối không tranh cãi. Hãy áp dụng quy tắc lắng nghe chân thành, sau đó đồng cảm: ''Dạ em hoàn toàn hiểu khó khăn của anh...'', tiếp theo cô lập vấn đề và giải thích giá trị thực tế của sản phẩm giúp họ tiết kiệm chi phí.</p>
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (152, 122, N'BÀI 1.1: Tầm quan trọng của việc bảo mật', N'Document', N'<p>1. Trong thời đại số, dữ liệu là tài sản quý giá nhất của doanh nghiệp. Rò rỉ thông tin có thể gây ra thiệt hại tài chính nghiêm trọng và làm mất uy tín thương hiệu. Nhân viên là tuyến phòng thủ đầu tiên và cũng là mục tiêu tấn công hàng đầu của các hacker.</p>
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (153, 122, N'BÀI 1.2: Các hình thức tấn công phổ biến', N'Document', N'<p>Nội dung bài học: Phishing (tấn công giả mạo) qua email là hình thức phổ biến nhất. Hacker sẽ gửi email giả mạo các tổ chức uy tín (như ngân hàng, bộ phận IT) để lừa nhân viên click vào link độc hại hoặc cung cấp mật khẩu. Ngoài ra còn có mã độc tống tiền (Ransomware) mã hóa dữ liệu của máy tính.</p>
INSERT INTO [Lessons] ([LessonID], [ModuleID], [Title], [ContentType], [ContentBody], [VideoURL], [Level], [SortOrder]) VALUES (154, 123, N'BÀI 2.1: Cách đặt mật khẩu an toàn', N'Document', N'<p>Nội dung bài học: Mật khẩu an toàn phải có độ dài tối thiểu 12 ký tự, bao gồm chữ hoa, chữ thường, chữ số và ký tự đặc biệt. Tuyệt đối không dùng thông tin cá nhân như ngày sinh, số điện thoại để đặt mật khẩu. Nên sử dụng phần mềm quản lý mật khẩu (Password Manager) để lưu trữ.</p>
